'use strict';

var valid = [];

// Consecutive requires without empty lines:
var test = {
	'code': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var tape = require( \'tape\' );',
		'var isnan = require( \'@stdlib/math/base/assert/is-nan\' );',
		'var abs = require( \'./../lib\' );',
		'',
		'',
		'// TESTS //',
		'',
		'tape( \'test\', function() {} );'
	].join( '\n' )
};
valid.push( test );

// Test file with FIXTURES section (empty lines around section header are OK):
test = {
	'code': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var tape = require( \'tape\' );',
		'var isnan = require( \'@stdlib/math/base/assert/is-nan\' );',
		'',
		'',
		'// FIXTURES //',
		'',
		'var data = require( \'./fixtures/data.json\' );',
		'var expected = require( \'./fixtures/expected.json\' );',
		'',
		'',
		'// TESTS //',
		'',
		'tape( \'test\', function() {} );'
	].join( '\n' )
};
valid.push( test );

// Single require statement (nothing to check):
test = {
	'code': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var main = require( \'./main.js\' );',
		'',
		'',
		'// EXPORTS //',
		'',
		'module.exports = main;'
	].join( '\n' )
};
valid.push( test );

// Require with property access: var foo = require( 'bar' ).baz;
test = {
	'code': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var isString = require( \'@stdlib/assert/is-string\' ).isPrimitive;',
		'var format = require( \'@stdlib/string/format\' );',
		'',
		'',
		'// MAIN //',
		'',
		'function main() {}'
	].join( '\n' )
};
valid.push( test );

// No require statements:
test = {
	'code': [
		'\'use strict\';',
		'',
		'// MAIN //',
		'',
		'function foo() {',
		'    return 1;',
		'}'
	].join( '\n' )
};
valid.push( test );

// Requires inside functions are not checked (only module-level):
test = {
	'code': [
		'\'use strict\';',
		'',
		'function helper() {',
		'    var a = require( \'a\' );',
		'',
		'    var b = require( \'b\' );',
		'}'
	].join( '\n' )
};
valid.push( test );

// Comments (non-header) between requires are allowed if no empty lines:
test = {
	'code': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var foo = require( \'foo\' );',
		'// A regular comment',
		'var bar = require( \'bar\' );'
	].join( '\n' )
};
valid.push( test );

// Multi-line require statements without empty lines between:
test = {
	'code': [
		'\'use strict\';',
		'',
		'// MODULES //',
		'',
		'var foo = require(',
		'    \'some/very/long/path/to/module\'',
		');',
		'var bar = require( \'bar\' );',
		'var baz = require(',
		'    \'another/long/path\'',
		');'
	].join( '\n' )
};
valid.push( test );

// Multiple non-require statements between requires without empty lines:
test = {
	'code': [
		'\'use strict\';',
		'',
		'var foo = require( \'foo\' );',
		'var x = 1;',
		'var y = 2;',
		'var z = x + y;',
		'var bar = require( \'bar\' );'
	].join( '\n' )
};
valid.push( test );


// EXPORTS //

module.exports = valid;
